import{_ as e,c as a,o as r,ai as o}from"./chunks/framework.TS84ywiI.js";const b=JSON.parse('{"title":"互联网公司 IT 技术面试题集","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md"}'),d={name:"getting-started.md"};function s(i,t,n,c,h,l){return r(),a("div",null,t[0]||(t[0]=[o('<h1 id="互联网公司-it-技术面试题集" tabindex="-1">互联网公司 IT 技术面试题集 <a class="header-anchor" href="#互联网公司-it-技术面试题集" aria-label="Permalink to &quot;互联网公司 IT 技术面试题集&quot;">​</a></h1><p><a href="https://github.com/doocs/coding-interview/blob/main/LICENSE" target="_blank" rel="noreferrer"><img src="https://badgen.net/github/license/doocs/leetcode?color=green" alt="license"></a><a href="https://github.com/doocs/coding-interview/stargazers" target="_blank" rel="noreferrer"><img src="https://badgen.net/github/stars/doocs/coding-interview" alt="stars"></a><a href="https://github.com/doocs/coding-interview/issues" target="_blank" rel="noreferrer"><img src="https://badgen.net/github/open-issues/doocs/coding-interview" alt="issues"></a><a href="https://github.com/doocs/coding-interview/network/members" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/forks/doocs/coding-interview.svg" alt="forks"></a><a href="http://makeapullrequest.com" target="_blank" rel="noreferrer"><img src="https://badgen.net/badge/PRs/welcome/green" alt="PRs Welcome"></a></p><h2 id="项目介绍" tabindex="-1">项目介绍 <a class="header-anchor" href="#项目介绍" aria-label="Permalink to &quot;项目介绍&quot;">​</a></h2><p>本仓库用于记录各大互联网公司 IT 技术面试高频题以及经典书籍读书笔记，包括《剑指 Offer》、《编程之美》、《代码整洁之道》等，抽空更新中。</p><h2 id="站点" tabindex="-1">站点 <a class="header-anchor" href="#站点" aria-label="Permalink to &quot;站点&quot;">​</a></h2><p><a href="https://interview.doocs.org" target="_blank" rel="noreferrer">https://interview.doocs.org</a></p><h2 id="书籍笔记" tabindex="-1">书籍笔记 <a class="header-anchor" href="#书籍笔记" aria-label="Permalink to &quot;书籍笔记&quot;">​</a></h2><h3 id="《剑指-offer》" tabindex="-1"><a href="/coding-interview">《剑指 Offer》</a> <a class="header-anchor" href="#《剑指-offer》" aria-label="Permalink to &quot;[《剑指 Offer》](/coding-interview.md)&quot;">​</a></h3><p>这本书选取的<a href="/coding-interview">题目</a>都是被各大公司面试官反复采用的编程题，极具实战意义。当然，如果一开始觉得这些题目比较难，也是很正常的，因为大公司的面试本身就不简单。我们逐步掌握书中总结的解题方法之后，再去面试大公司，将会轻松很多。</p><p>推荐三个在线刷《剑指 Offer》的平台，个人比较倾向于 <a href="https://leetcode.cn/problemset/lcof/" target="_blank" rel="noreferrer">LeetCode 中国</a> 。</p><ul><li><a href="https://leetcode.cn/problemset/lcof/" target="_blank" rel="noreferrer">LeetCode 中国</a>：近期上线，支持多种编程语言，墙裂推荐。</li><li><a href="https://www.acwing.com/problem/" target="_blank" rel="noreferrer">AcWing</a>：支持 Java11。团队成员来自北大清华，剑指 Offer 第二版题目都有。</li><li><a href="https://www.nowcoder.com/ta/coding-interviews" target="_blank" rel="noreferrer">NowCoder</a>：这个应该大多数人都知道，但是没有剑指 Offer 第二版新增的题目。</li></ul><h3 id="《代码整洁之道》" tabindex="-1"><a href="/clean-code">《代码整洁之道》</a> <a class="header-anchor" href="#《代码整洁之道》" aria-label="Permalink to &quot;[《代码整洁之道》](/clean-code.md)&quot;">​</a></h3><p>这本书名为 <em>Clean Code</em>，乃是 Object Mentor（鲍勃大叔开办的技术咨询和培训公司）一干大牛在编程方面的经验累积。写整洁代码，需要遵循大量的小技巧，贯彻刻苦习得的“整洁感”。</p><p>作者 Robert C. Martin 在书中阐述了代码各个方面如何做到整洁的经验与最佳实践。我们若能长期遵照这些经验编写代码，所谓“代码感”也就自然而然滋生出来。</p><h3 id="《阿里巴巴-java-开发手册》" tabindex="-1"><a href="/effective-coding">《阿里巴巴 Java 开发手册》</a> <a class="header-anchor" href="#《阿里巴巴-java-开发手册》" aria-label="Permalink to &quot;[《阿里巴巴 Java 开发手册》](/effective-coding.md)&quot;">​</a></h3><p>别人都说我们是搬砖的码农，但我们知道自己是追求个性的艺术家。也许我们不会过多在意自己的外表和穿着，但在我们不羁的外表下，骨子里追求着代码的美、系统的美、设计的美，代码规范其实就是一个对程序美的定义。</p><h3 id="《枕边算法书》" tabindex="-1"><a href="/algorithm-stories">《枕边算法书》</a> <a class="header-anchor" href="#《枕边算法书》" aria-label="Permalink to &quot;[《枕边算法书》](/algorithm-stories.md)&quot;">​</a></h3><p>这本书，我是把它当作一本故事书来读的，里面的部分知识点还挺有意思。</p><h3 id="《effective-java》" tabindex="-1"><a href="/effective-java">《Effective Java》</a> <a class="header-anchor" href="#《effective-java》" aria-label="Permalink to &quot;[《Effective Java》](/effective-java.md)&quot;">​</a></h3><p>这本书共包含了 78 个条目，每个条目讨论一条规则。它适用于任何具有实际 Java 工作经验的工程师，对于高级工程师，也能够提供一些发人深思的东西，是所有 Java 工程师必读书籍之一。</p><hr><h2 id="doocs-社区优质项目" tabindex="-1">Doocs 社区优质项目 <a class="header-anchor" href="#doocs-社区优质项目" aria-label="Permalink to &quot;Doocs 社区优质项目&quot;">​</a></h2><p>Doocs 技术社区，致力于打造一个内容完整、持续成长的互联网开发者学习生态圈！以下是 Doocs 旗下的一些优秀项目，欢迎各位开发者朋友持续保持关注。</p><table tabindex="0"><thead><tr><th>#</th><th>项目</th><th>描述</th><th>热度</th></tr></thead><tbody><tr><td>1</td><td><a href="https://github.com/doocs/advanced-java" target="_blank" rel="noreferrer">advanced-java</a></td><td>互联网 Java 工程师进阶知识完全扫盲：涵盖高并发、分布式、高可用、微服务、海量数据处理等领域知识。</td><td><img src="https://badgen.net/github/stars/doocs/advanced-java" alt=""> <br><img src="https://badgen.net/github/forks/doocs/advanced-java" alt=""></td></tr><tr><td>2</td><td><a href="https://github.com/doocs/leetcode" target="_blank" rel="noreferrer">leetcode</a></td><td>多种编程语言实现 LeetCode、《剑指 Offer（第 2 版）》、《程序员面试金典（第 6 版）》题解。</td><td><img src="https://badgen.net/github/stars/doocs/leetcode" alt=""> <br><img src="https://badgen.net/github/forks/doocs/leetcode" alt=""></td></tr><tr><td>3</td><td><a href="https://github.com/doocs/source-code-hunter" target="_blank" rel="noreferrer">source-code-hunter</a></td><td>互联网常用组件框架源码分析。</td><td><img src="https://badgen.net/github/stars/doocs/source-code-hunter" alt=""> <br><img src="https://badgen.net/github/forks/doocs/source-code-hunter" alt=""></td></tr><tr><td>4</td><td><a href="https://github.com/doocs/jvm" target="_blank" rel="noreferrer">jvm</a></td><td>Java 虚拟机底层原理知识总结。</td><td><img src="https://badgen.net/github/stars/doocs/jvm" alt=""> <br><img src="https://badgen.net/github/forks/doocs/jvm" alt=""></td></tr><tr><td>5</td><td><a href="https://github.com/doocs/coding-interview" target="_blank" rel="noreferrer">coding-interview</a></td><td>代码面试题集，包括《剑指 Offer》、《编程之美》等。</td><td><img src="https://badgen.net/github/stars/doocs/coding-interview" alt=""> <br><img src="https://badgen.net/github/forks/doocs/coding-interview" alt=""></td></tr><tr><td>6</td><td><a href="https://github.com/doocs/md" target="_blank" rel="noreferrer">md</a></td><td>一款高度简洁的微信 Markdown 编辑器。</td><td><img src="https://badgen.net/github/stars/doocs/md" alt=""> <br><img src="https://badgen.net/github/forks/doocs/md" alt=""></td></tr><tr><td>7</td><td><a href="https://github.com/doocs/technical-books" target="_blank" rel="noreferrer">technical-books</a></td><td>值得一看的技术书籍列表。</td><td><img src="https://badgen.net/github/stars/doocs/technical-books" alt=""> <br><img src="https://badgen.net/github/forks/doocs/technical-books" alt=""></td></tr></tbody></table><h2 id="贡献者" tabindex="-1">贡献者 <a class="header-anchor" href="#贡献者" aria-label="Permalink to &quot;贡献者&quot;">​</a></h2><p>感谢以下所有朋友对 <a href="https://github.com/doocs" target="_blank" rel="noreferrer">Doocs 技术社区</a> 所做出的贡献，<a href="https://doocs.github.io/#/?id=how-to-join" target="_blank" rel="noreferrer">参与项目维护请戳这儿</a>。</p><p><a href="https://opencollective.com/doocs/contributors.svg?width=890&amp;button=true"><img src="https://opencollective.com/doocs/contributors.svg?width=890&amp;button=false"></a></p>',27)]))}const f=e(d,[["render",s]]);export{b as __pageData,f as default};
